func (a *adapter) CreateOverride(ctx context.Context, input llmcost.CreateOverrideInput) (llmcost.Price, error) {
	return entutils.TransactingRepo(ctx, a, func(ctx context.Context, a *adapter) (llmcost.Price, error) {
		if err := input.Validate(); err != nil {
			return llmcost.Price{}, err
		}
		_, _ = a.db.LLMCostPrice.Update().
			Where(pricedb.DeletedAtIsNil(), pricedb.NamespaceEQ(input.Namespace), pricedb.ProviderEQ(string(input.Provider)), pricedb.ModelIDEQ(input.ModelID), pricedb.SourceEQ(string(llmcost.PriceSourceManual))).
			SetDeletedAt(clock.Now()).Save(ctx)
		entity, err := a.db.LLMCostPrice.Create().SetNamespace(input.Namespace).SetSource(string(llmcost.PriceSourceManual)).Save(ctx)
		if err != nil {
			if entdb.IsConstraintError(err) {
				err = models.NewGenericConflictError(err)
			}
			return llmcost.Price{}, fmt.Errorf("failed to create override: %w", err)
		}
		return mapPriceFromEntity(entity)
	})
}

return transaction.Run(ctx, s.adapter, func(ctx context.Context) (pagination.Result[llmcost.Price], error) {
	result, err := s.adapter.ListPrices(ctx, input)
	if err != nil { return pagination.Result[llmcost.Price]{}, err }
	if input.Namespace == "" || len(result.Items) == 0 || sourceFilterExcludesManual(input.Source) {
		return result, nil
	}
	overrides, err := s.adapter.ListOverrides(ctx, llmcost.ListOverridesInput{Namespace: input.Namespace, Provider: input.Provider, ModelID: input.ModelID})
	if err != nil { return pagination.Result[llmcost.Price]{}, err }
	overrideMap := make(map[overrideKey]llmcost.Price, len(overrides.Items))
	for _, o := range overrides.Items { overrideMap[overrideKey{string(o.Provider), o.ModelID}] = o }
	for i, p := range result.Items {
		if o, ok := overrideMap[overrideKey{string(p.Provider), p.ModelID}]; ok { result.Items[i] = o }
	}
	return result, nil
})

func (j *SyncJob) Run(ctx context.Context) error {
	var allPrices []llmcost.SourcePrice
	for _, f := range j.fetchers {
		prices, err := f.Fetch(ctx)
		if err != nil {
			j.logger.Error("failed to fetch prices", "source", f.Source(), "error", err)
			continue
		}
		for _, p := range prices {
			provider, modelID := j.normalizer.Normalize(p.ModelID, string(p.Provider))
			p.Provider = llmcost.Provider(provider)
			p.ModelID = modelID
			allPrices = append(allPrices, p)
		}
	}
	allPrices = deduplicateSourcePrices(allPrices)
	if j.filter != nil {
		filtered := allPrices[:0]
		for _, p := range allPrices { if j.filter(p) { filtered = append(filtered, p) } }
		allPrices = filtered
	}
	return j.reconciler.Reconcile(ctx, allPrices)
}
